import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';

// ⚠️ DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  city: string; // City name
  temperature: number; // Current temperature
  condition: string; // Weather condition (Sunny, Cloudy, Rainy, etc.)
  humidity: number; // Humidity percentage
  windSpeed: number; // Wind speed
  unit: string; // Temperature unit (C or F)
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>; // 5-day forecast array
}

function useComponent(props: Props) {
  const conditionIcon = useMemo(() => {
    const cond = props.condition.toLowerCase();
    if (cond.includes('sun') || cond.includes('clear')) return 'sun';
    if (cond.includes('rain')) return 'cloud-rain';
    if (cond.includes('cloud')) return 'cloud';
    return 'cloud';
  }, [props.condition]);

  return { conditionIcon };
}

export default function Component(props: Props) {
  const { conditionIcon } = useComponent(props);

  return (
    <Card shadow="md" padding={24} radius="lg" style={{ maxWidth: '400px', margin: 'auto' }}>
      <Stack gap={16}>
        <Row justify="between" align="center">
          <Heading level={2}>{props.city}</Heading>
          <Badge variant="primary">{props.unit}</Badge>
        </Row>
        <Stack align="center" gap={8}>
          <Heading level={1}>{props.temperature}°</Heading>
          <Icon name={conditionIcon} size={48} />
          <Text variant="body">{props.condition}</Text>
        </Stack>
        <Row justify="center" gap={32}>
          <Text variant="label">Humidity: {props.humidity}%</Text>
          <Text variant="label">Wind: {props.windSpeed} km/h</Text>
        </Row>
        <Divider />
        <Stack direction="horizontal" justify="between">
          {props.forecast.map((f, i) => (
            <Stack key={i} align="center" gap={4}>
              <Text variant="caption">{f.day}</Text>
              <Icon name={f.icon || 'sun'} size={24} />
              <Text variant="bodySmall" weight="semibold">{f.high}°/{f.low}°</Text>
            </Stack>
          ))}
        </Stack>
      </Stack>
    </Card>
  );
}

