import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';

// ⚠️ DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>;
  columns: Array<{ id?: string; name?: string }>; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
  onTaskUpdate?: (data: Record<string, unknown>) => void; // Action: Task Updated
}

function useComponent(props: Props) {
  const handleTaskUpdate = useCallback((data: Record<string, unknown>) => {
    props.onTaskUpdate?.(data);
  }, [props.onTaskUpdate]);

  const [tasks, setTasks] = useState(props.tasks);
  const [addingTo, setAddingTo] = useState<string | null>(null);
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<string>('medium');
  const [editingTaskId, setEditingTaskId] = useState<string | null>(null);

  const columnTasks = useMemo(() => {
    return props.columns.map(col => ({
      ...col,
      tasks: tasks.filter(t => t.column === col.id) || []
    }));
  }, [props.columns, tasks]);

  const addTask = (colId: string) => {
    const newTask = {
      id: Math.random().toString(36).substr(2, 9),
      title: newTaskTitle,
      priority: newTaskPriority as 'low' | 'medium' | 'high',
      column: colId,
      assignee: '??',
      dueDate: new Date().toISOString()
    };
    setTasks(prev => [...prev, newTask]);
    handleTaskUpdate({ type: 'add', task: newTask });
    setAddingTo(null);
    setNewTaskTitle('');
  };

  const editTask = (taskId: string, newTitle: string) => {
    const updatedTasks = tasks.map(t => t.id === taskId ? { ...t, title: newTitle } : t);
    setTasks(updatedTasks);
    handleTaskUpdate({ type: 'edit', taskId, title: newTitle });
    setEditingTaskId(null);
  };

  const moveTask = (taskId: string, newColId: string) => {
    const updatedTasks = tasks.map(t => t.id === taskId ? { ...t, column: newColId } : t);
    setTasks(updatedTasks);
    handleTaskUpdate({ type: 'move', taskId, column: newColId });
  };

  return { columnTasks, addingTo, setAddingTo, newTaskTitle, setNewTaskTitle, newTaskPriority, setNewTaskPriority, addTask, moveTask, editingTaskId, setEditingTaskId, editTask };
}

export default function Component(props: Props) {
  const { columnTasks, addingTo, setAddingTo, newTaskTitle, setNewTaskTitle, newTaskPriority, setNewTaskPriority, addTask, moveTask, editingTaskId, setEditingTaskId, editTask } = useComponent(props);

  return (
    <Container maxWidth="3xl" padding={24}>
      <Stack gap={24}>
        <Row justify="between" align="center">
          <Heading level={2}>Project Board</Heading>
          <Badge variant="primary">{props.tasks.length} total tasks</Badge>
        </Row>
        <Row align="start" gap={16}>
          {columnTasks.map(col => (
            <Box key={col.id} background="var(--ggui-color-surfaceVariant, #f4f4f5)" borderRadius={8} padding={16} style={{ flex: 1, minWidth: 280 }}>
              <Stack gap={16}>
                <Row justify="between" align="center">
                  <Heading level={4}>{col.name || 'Column'}</Heading>
                  <Badge>{col.tasks.length}</Badge>
                </Row>
                <Stack gap={8}>
                  {col.tasks.map(task => (
                    <Card key={task.id} padding={16} shadow="sm">
                      <Stack gap={8}>
                        {editingTaskId === task.id ? (
                          <Input value={task.title} onChange={(val) => editTask(task.id!, val)} />
                        ) : (
                          <Text variant="body" weight="semibold" onDoubleClick={() => setEditingTaskId(task.id!)}>{task.title}</Text>
                        )}
                        <Row justify="between" align="center">
                          <Badge variant={task.priority === 'high' ? 'error' : task.priority === 'medium' ? 'warning' : 'info'}>{task.priority}</Badge>
                          <Avatar name={task.assignee || '??'} size={24} shape="circle" />
                        </Row>
                        <Row justify="end" gap={4}>
                          <Button variant="ghost" size="xs" onClick={() => setEditingTaskId(task.id!)}>Edit</Button>
                          <Dropdown
                            trigger={<Button variant="outline" size="xs">Move</Button>}
                            options={props.columns
                              .filter(c => c.id !== col.id)
                              .map(c => ({ value: c.id || '', label: `To ${c.name}` }))}
                            value=""
                            onChange={(val) => moveTask(task.id || '', val)}
                            placement="bottom-end"
                          />
                        </Row>
                      </Stack>
                    </Card>
                  ))}
                </Stack>
                {addingTo === col.id ? (
                  <Stack gap={8}>
                    <Input label="Title" value={newTaskTitle} onChange={setNewTaskTitle} placeholder="Task title" />
                    <Select label="Priority" options={[{value: 'low', label: 'Low'}, {value: 'medium', label: 'Medium'}, {value: 'high', label: 'High'}]} value={newTaskPriority} onChange={setNewTaskPriority} />
                    <Row gap={8}>
                      <Button size="sm" onClick={() => addTask(col.id!)}>Save</Button>
                      <Button size="sm" variant="ghost" onClick={() => setAddingTo(null)}>Cancel</Button>
                    </Row>
                  </Stack>
                ) : (
                  <Button variant="ghost" leftIcon={<Icon name="plus" size={16} />} onClick={() => setAddingTo(col.id!)}>
                    Add Task
                  </Button>
                )}
              </Stack>
            </Box>
          ))}
        </Row>
      </Stack>
    </Container>
  );
}

