import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';

// ⚠️ DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  elements: Array<{ atomicNumber?: number; symbol?: string; name?: string; atomicWeight?: number; category?: string; row?: number; col?: number }>; // Full periodic table element data
}

function useComponent(props: Props) {
  const [filter, setFilter] = useState('');
  const [selected, setSelected] = useState<any>(null);

  const CATEGORY_COLORS: Record<string, string> = {
    'alkali metal': 'var(--ggui-color-primary-300)',
    'alkaline earth metal': 'var(--ggui-color-primary-200)',
    'transition metal': 'var(--ggui-color-primary-400)',
    'post-transition metal': 'var(--ggui-color-primary-500)',
    'metalloid': 'var(--ggui-color-info-300)',
    'nonmetal': 'var(--ggui-color-success-300)',
    'noble gas': 'var(--ggui-color-warning-300)',
    'lanthanide': 'var(--ggui-color-error-300)',
    'actinide': 'var(--ggui-color-error-400)',
  };

  const filtered = useMemo(() => {
    const f = filter.toLowerCase();
    return props.elements.filter(
      (e) =>
        e.name?.toLowerCase().includes(f) ||
        e.symbol?.toLowerCase().includes(f)
    );
  }, [props.elements, filter]);

  return { filter, setFilter, selected, setSelected, filtered, CATEGORY_COLORS };
}

export default function Component(props: Props) {
  const { filter, setFilter, selected, setSelected, filtered, CATEGORY_COLORS } = useComponent(props);

  return (
    <Container maxWidth="3xl" padding={24}>
      <Stack gap={16}>
        <Heading level={1}>Periodic Table</Heading>
        <SearchField value={filter} onChange={setFilter} placeholder="Search by name or symbol..." />
        <Row gap={8} wrap>
          {Object.entries(CATEGORY_COLORS).map(([cat, color]) => (
            <Tag key={cat} variant="default" style={{ backgroundColor: color }}>{cat}</Tag>
          ))}
        </Row>
        <Box style={{ display: 'grid', gridTemplateColumns: 'repeat(18, 1fr)', gap: 'var(--ggui-spacing-1)' }}>
          {props.elements.map((el) => (
            <Card
              key={el.atomicNumber}
              as={Clickable}
              onClick={() => setSelected(el)}
              style={{
                gridRow: el.row,
                gridColumn: el.col,
                opacity: !filter || filtered.includes(el) ? 1 : 0.2,
                backgroundColor: selected?.atomicNumber === el.atomicNumber ? 'var(--ggui-color-primary-100)' : (el.category ? CATEGORY_COLORS[el.category.toLowerCase()] : 'var(--ggui-color-surfaceVariant)'),
              }}
              padding={4}
            >
              <Text variant="caption">{el.atomicNumber}</Text>
              <Heading level={4} align="center">{el.symbol}</Heading>
            </Card>
          ))}
        </Box>
        {selected && (
          <Card padding={16}>
            <Heading level={3}>{selected.name} ({selected.symbol})</Heading>
            <Text>Atomic Number: {selected.atomicNumber}</Text>
            <Text>Atomic Weight: {selected.atomicWeight}</Text>
            <Text>Category: {selected.category}</Text>
            <Button variant="ghost" onClick={() => setSelected(null)}>Close</Button>
          </Card>
        )}
      </Stack>
    </Container>
  );
}

