import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';

// ⚠️ DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  product: { id?: string; name?: string; price?: number; currency?: string; rating?: number; reviewCount?: number; stock?: number; description?: string; specifications?: unknown[]; reviews?: unknown[] }; // Product object with id, name, price, currency, rating, stock, description, specifications[], reviews[]
  onAddToCart?: (data: Record<string, unknown>) => void; // Action: Add to Cart
}

function useComponent(props: Props) {
  const handleAddToCart = useCallback((data: Record<string, unknown>) => {
    props.onAddToCart?.(data);
  }, [props.onAddToCart]);

  const [quantity, setQuantity] = useState(1);
  const [activeTab, setActiveTab] = useState('description');

  const stock = props.product.stock || 0;
  const canAdd = stock > 0;

  const addToCart = () => {
    handleAddToCart({ productId: props.product.id, quantity });
  };

  return { quantity, setQuantity, activeTab, setActiveTab, stock, canAdd, addToCart };
}

export default function Component(props: Props) {
  const { quantity, setQuantity, activeTab, setActiveTab, stock, canAdd, addToCart } = useComponent(props);
  const { name, price, currency, rating, description, specifications, reviews } = props.product;

  return (
    <Container padding={24}>
      <Stack direction="horizontal" gap={32}>
        <Box background="var(--ggui-color-surfaceVariant)" borderRadius="lg" padding={48} style={{ flex: 1, minWidth: 300 }}>
          <Heading level={3}>{name}</Heading>
        </Box>
        <Stack gap={16} style={{ flex: 1 }}>
          <Heading level={1}>{name}</Heading>
          <Text variant="bodyLarge">{currency}{price}</Text>
          <Badge variant={stock > 0 ? 'success' : 'error'}>{stock > 0 ? `In Stock (${stock})` : 'Out of Stock'}</Badge>
          <Row gap={8} align="center">
            <Button variant="secondary" onClick={() => setQuantity(Math.max(1, quantity - 1))}>-</Button>
            <Text>{quantity}</Text>
            <Button variant="secondary" onClick={() => setQuantity(Math.min(stock, quantity + 1))}>+</Button>
            <Button disabled={!canAdd} onClick={addToCart}>Add to Cart</Button>
          </Row>
        </Stack>
      </Stack>

      <Box marginY={32}>
        <Tabs 
          activeKey={activeTab} 
          onChange={setActiveTab}
          items={[
            { key: 'description', label: 'Description', content: <Text>{description}</Text> },
            { key: 'specifications', label: 'Specifications', content: <Table columns={[{key: 'key', header: 'Feature'}, {key: 'value', header: 'Detail'}]} data={(specifications as any[]) || []} /> },
            { key: 'reviews', label: 'Reviews', content: <Stack gap={16}>{(reviews as any[])?.map((r, i) => <Card key={i}><Text variant="label">{r.author}</Text><Text>{r.text}</Text></Card>)}</Stack> }
          ]} 
        />
      </Box>
    </Container>
  );
}

