import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';

// ⚠️ DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  initialProfile: { name?: string; email?: string; avatar?: string; role?: string; emailNotifications?: boolean; theme?: string }; // Pre-filled profile data for editing (all fields optional)
  avatarOptions: string[]; // Available avatar emojis to choose from
  roleOptions: string[]; // Available role options for the dropdown
  onComplete?: (data: Record<string, unknown>) => void; // Action: Complete Setup
}

function useComponent(props: Props) {
  const handleComplete = useCallback((data: Record<string, unknown>) => {
    props.onComplete?.(data);
  }, [props.onComplete]);

  const [currentStep, setCurrentStep] = useState(0);
  const [touched, setTouched] = useState({ name: false, email: false });
  const [formData, setFormData] = useState({
    name: props.initialProfile.name || '',
    email: props.initialProfile.email || '',
    avatar: props.initialProfile.avatar || props.avatarOptions[0],
    role: props.initialProfile.role || '',
    emailNotifications: props.initialProfile.emailNotifications ?? true,
    theme: props.initialProfile.theme || 'light',
  });

  const updateField = (field: string, value: any) => {
    setFormData(d => ({ ...d, [field]: value }));
    setTouched(t => ({ ...t, [field]: true }));
  };

  const isValidEmail = (email: string) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);

  const canNext = useMemo(() => {
    if (currentStep === 0) {
      return formData.name.trim() !== '' && isValidEmail(formData.email);
    }
    return true; // Step 1 and 2 don't have hard validation requirements
  }, [currentStep, formData]);

  const steps = ['Profile Setup', 'Preferences', 'Review'];
  const progress = ((currentStep + 1) / steps.length);

  return { currentStep, setCurrentStep, formData, updateField, canNext, steps, progress, handleComplete, isValidEmail, touched };
}

export default function Component(props: Props) {
  const { currentStep, setCurrentStep, formData, updateField, canNext, steps, progress, handleComplete, isValidEmail, touched } = useComponent(props);

  return (
    <Container maxWidth="sm" padding={24}>
      <Stack gap={16}>
        <Heading level={2}>{steps[currentStep]}</Heading>
        <Progress value={progress * 100} />

        <Box paddingY={16}>
          {currentStep === 0 && (
            <Stack gap={16}>
              <FormField label="Name" required error={touched.name && formData.name.trim() === '' ? 'Name is required' : undefined}><Input value={formData.name} onChange={(v) => updateField('name', v)} /></FormField>
              <FormField label="Email" required error={touched.email && !isValidEmail(formData.email) ? 'Invalid email format' : undefined}><Input type="email" value={formData.email} onChange={(v) => updateField('email', v)} /></FormField>
              <Text variant="label">Select Avatar</Text>
              <Row gap={8}>
                {props.avatarOptions.map(emoji => (
                  <Box as={Clickable} key={emoji} onClick={() => updateField('avatar', emoji)} borderRadius="full" style={{ border: formData.avatar === emoji ? '2px solid var(--ggui-color-primary-600, #0284c7)' : '2px solid transparent' }}>
                    <Avatar name={emoji} />
                  </Box>
                ))}
              </Row>
            </Stack>
          )}
          {currentStep === 1 && (
            <Stack gap={16}>
              <FormField label="Role"><Select value={formData.role} onChange={(v) => updateField('role', v)} options={props.roleOptions.map(r => ({ value: r, label: r }))} /></FormField>
              <Toggle label="Email notifications" checked={formData.emailNotifications} onChange={(v) => updateField('emailNotifications', v)} />
              <Toggle label="Dark theme" checked={formData.theme === 'dark'} onChange={(v) => updateField('theme', v ? 'dark' : 'light')} />
            </Stack>
          )}
          {currentStep === 2 && (
            <Card padding={16}>
              <Stack gap={8}>
                <Text variant="label">Name: {formData.name}</Text>
                <Text variant="label">Email: {formData.email}</Text>
                <Text variant="label">Role: {formData.role}</Text>
                <Text variant="label">Notifications: {formData.emailNotifications ? 'Enabled' : 'Disabled'}</Text>
              </Stack>
            </Card>
          )}
        </Box>

        <Row justify="between">
          <Button variant="outline" disabled={currentStep === 0} onClick={() => setCurrentStep(s => s - 1)}>Back</Button>
          {currentStep < 2 ? (
            <Button disabled={!canNext} onClick={() => setCurrentStep(s => s + 1)}>Next</Button>
          ) : (
            <Button variant="primary" onClick={() => handleComplete(formData)}>Complete Setup</Button>
          )}
        </Row>
      </Stack>
    </Container>
  );
}
